local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameSwordCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameSwordCtrl = LxClass("LMatchThreeGameSwordCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local Tweening = DG.Tweening
local Ease = Tweening.Ease

-- 一节点增加的大小
local OneNodeAdd = 0.1

local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)

local YXTouchManager = CS.YXTouchManager
local math = math
local Vector3 = Vector3

-----------------------------------------------------------------
function LMatchThreeGameSwordCtrl:LMatchThreeGameSwordCtrl()

end

-- 销毁
function LMatchThreeGameSwordCtrl:OnDestroy()
    if self._swordSeq then
        self._swordSeq:Kill(false)
        self._swordSeq = nil
    end
end

-- 初始化
function LMatchThreeGameSwordCtrl:Init()

end

-- 初始化trans
function LMatchThreeGameSwordCtrl:InitTrans()
    if self._trans then
        return
    end
    local root = self:GetMap():GetMapTrans()
    local trans = CS.FindTrans(root, "LayerRoot/Sword")
    CS.ShowObject(trans, false)
    local obj = LxUnity.InstantObject(trans.gameObject)
    trans = obj.transform
    CS.ShowObject(trans, true)

    self._trans = trans
    self._iconTrans = CS.FindTrans(trans, "Img0/Icon")
    self._iconRoot = self._iconTrans.parent
    self._iconSprite = self._iconTrans:GetComponent(typeSpriteRenderer)
    self._iconSpriteInitSize = self._iconSprite.size
end

-- 获取保存ctrl
function LMatchThreeGameSwordCtrl:InitGetCtrl()
    if not self._posCtrl then
        self._posCtrl = self:GetCtrl("Pos")
    end
    if not self._objCtrl then
        self._objCtrl = self:GetCtrl("Objs")
    end
    if not self._lineCtrl then
        self._lineCtrl = self:GetCtrl("Line")
    end
end

-- 显示/隐藏，传0为隐藏
function LMatchThreeGameSwordCtrl:Show(index, nodeNum)
    if self._trans then
        CS.ShowObject(self._trans, nodeNum > 0)
    end
    if nodeNum <= 0 then
        return
    end

    self:InitTrans()
    self:InitGetCtrl()
    local obj = self._objCtrl:GetObj(index)
    self._trans:SetParent(obj:GetTransform(), false)
    self._trans.localPosition       = Vector3(0, 0, 0)
    self._trans.localScale          = Vector3(1, 1, 1)
    self._trans.localRotation       = Quaternion.identity
    self._iconRoot.localEulerAngles = Vector3(0, 0, 0)

    local w                         = OneNodeAdd * nodeNum + self._iconSpriteInitSize.x
    self._iconSprite.size           = Vector2(w, self._iconSpriteInitSize.y)
end

-- 开始挥剑
function LMatchThreeGameSwordCtrl:StartSword(endFunc)
    local trans = self._iconRoot
    local seq = Tweening.DOTween.Sequence()
    local tw1 = YXTween.TweenFloat(0, 15, 0.10, function(ival)
        trans.localEulerAngles = Vector3(0, 0, ival)
    end)
    local tw2 = YXTween.TweenFloat(20, -260, 0.4, function(ival)
        trans.localEulerAngles = Vector3(0, 0, ival)
    end)
    seq:Append(tw1)
    seq:AppendInterval(0.05)
    seq:Append(tw2)
    seq:OnComplete(function()
        self._swordSeq = nil
        if endFunc then
            endFunc()
        end
        CS.ShowObject(self._trans, false)
    end)

    seq:Play()
    self._swordSeq = seq
end

return LMatchThreeGameSwordCtrl
